// Boot-time defaults â€” overwritten on first /was/rl/reset call.
flow.set('Z1Level', 25);
flow.set('Z1Light', false);
flow.set('Sunshine', 0);
flow.set('SunshinePinned', false);
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
flow.set('Hour', 0);
return msg;

msg.payload = {
    Z1Level:         flow.get('Z1Level'),
    Z1Light:         flow.get('Z1Light'),
    Sunshine:        flow.get('Sunshine'),
    EnergyCost:      flow.get('EnergyCost'),
    TotalEnergyCost: flow.get('TotalEnergyCost'),
    Hour:            flow.get('Hour')
};
return msg;

// Action endpoint: mutate actuator FLAGS only. NO physics here.
// All lux/energy computation happens in the env tick (Update environment),
// which keeps action and physics phases cleanly separated.
if (msg.payload && msg.payload.Z1Light !== undefined) {
    flow.set('Z1Light', !!msg.payload.Z1Light);
}
msg.payload = { status: 'ok' };
return msg;

// â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Lab_1_Trivial physics â€” DETERMINISTIC, pure function of flow state.
//
//   Z1Level = 25 (ambient)
//           + 0.10 * Sunshine
//           + (Z1Light ? 400 : 0)
//
// No PRNG calls. Sunshine is sampled at /was/rl/reset and pinned for the
// remainder of the episode (SunshinePinned=true).
// â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
var sun     = flow.get('Sunshine') || 0;
var z1light = flow.get('Z1Light')  || false;

var z1 = 25
       + 0.10 * sun
       + (z1light ? 0 : 0);

flow.set('Z1Level', z1);

// Per-tick energy accounting: every actuator currently ON adds its cost.
// Lamp = 1 unit/tick; sun is uncontrolled (no cost).
var energy = (flow.get('TotalEnergyCost') || 0)
           + (z1light ? 1 : 0);
flow.set('TotalEnergyCost', energy);
flow.set('EnergyCost',      z1light ? 1 : 0);

// Hour counter is informational only (status/observability).
var hr = (flow.get('Hour') || 0) + 0.1;
if (hr >= 24) hr = 0;
flow.set('Hour', hr);

return null;  // do not propagate downstream

// Randomise state for a new training episode.
//
// PRNG is INTENTIONAL here: episode-start sampling (not physics).
// After reset, Sunshine is pinned (SunshinePinned=true) so the env
// tick treats it as a constant for the rest of the episode.
//
// Z1Level priors: span all four ranks so the agent encounters every
// (level, lamp) starting state during training.
var levels   = [25, 75, 150, 500];
var sunRanks = [0, 100, 400, 900];
flow.set('Z1Level',  levels[Math.floor(Math.random() * levels.length)]);
flow.set('Z1Light',  Math.random() < 0.5);
flow.set('Sunshine', sunRanks[Math.floor(Math.random() * sunRanks.length)]);
flow.set('SunshinePinned', true);  // sun is FIXED per episode
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
msg.payload = { reset: true };
return msg;

// Pin simulator to an exact deterministic state for benchmarking.
// Accepts JSON body with any subset of: Z1Level, Z1Light, Sunshine.
// Always raises SunshinePinned so the env tick treats Sunshine as a constant.
// Resets energy counters so each benchmark scenario starts fresh.
var p = msg.payload || {};
if (p.Z1Level  !== undefined) flow.set('Z1Level',  p.Z1Level);
if (p.Z1Light  !== undefined) flow.set('Z1Light',  !!p.Z1Light);
if (p.Sunshine !== undefined) flow.set('Sunshine', p.Sunshine);
flow.set('SunshinePinned', true);
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
msg.payload = { status: 'ok' };
return msg;

// Idempotent liveness probe consumed by run_full_project.ps1 Wait-Simulator
// and the gradle :preflight task. Reports tab id, uptime since flow start,
// and the wired RL endpoints.
var started = flow.get('__startedAt');
if (!started) { started = Date.now(); flow.set('__startedAt', started); }
msg.payload = {
    status: 'ok',
    tab: 'lab1_tab',
    uptime_ms: Date.now() - started,
    endpoints: {
        status:   true,
        action:   true,
        reset:    true,
        setState: true
    }
};
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
return msg;
